class SegmentTree {
private:
    struct Node {
        Point minPoint;
        bool isLazy;
        Point lazyValue;
    };

    std::vector<Node> tree;
    int size;

    inline void propagate(int node, int start, int end) {
        if (!tree[node].isLazy)
            return;

        if (start != end) {
            tree[node << 1].minPoint = tree[node].lazyValue;
            tree[(node << 1) | 1].minPoint = tree[node].lazyValue;
            tree[node << 1].isLazy = true;
            tree[(node << 1) | 1].isLazy = true;
            tree[node << 1].lazyValue = tree[node].lazyValue;
            tree[(node << 1) | 1].lazyValue = tree[node].lazyValue;
        }

        tree[node].minPoint = tree[node].lazyValue;
        tree[node].isLazy = false;
    }

    inline void updateNode(int node) {
        if (comparePoints(tree[node << 1].minPoint, tree[(node << 1) | 1].minPoint))
            tree[node].minPoint = tree[node << 1].minPoint;
        else
            tree[node].minPoint = tree[(node << 1) | 1].minPoint;
    }

    void build(std::vector<Point>& arr, int node, int start, int end) {
        if (start == end)
            tree[node].minPoint = arr[start];
        else {
            int mid = (start + end) >> 1;
            build(arr, node << 1, start, mid);
            build(arr, (node << 1) | 1, mid + 1, end);
            updateNode(node);
        }
    }

    void updateRange(int left, int right, const Point& newValue, int node, int start, int end) {
        propagate(node, start, end);

        if (right < start || end < left)
            return;

        if (left <= start && end <= right) {
            tree[node].minPoint = newValue;
            tree[node].isLazy = true;
            tree[node].lazyValue = newValue;
            return;
        }

        int mid = (start + end) >> 1;
        updateRange(left, right, newValue, node << 1, start, mid);
        updateRange(left, right, newValue, (node << 1) | 1, mid + 1, end);
        updateNode(node);
    }

    Point queryRange(int left, int right, int node, int start, int end) {
        propagate(node, start, end);

        if (right < start || end < left)
            return {static_cast<char>(INT_MAX), static_cast<int>(INT_MAX)};

        if (left <= start && end <= right)
            return tree[node].minPoint;

        int mid = (start + end) >> 1;
        auto leftResult = queryRange(left, right, node << 1, start, mid);
        auto rightResult = queryRange(left, right, (node << 1) | 1, mid + 1, end);

        if (comparePoints(leftResult, rightResult))
            return leftResult;
        return rightResult;
    }

public:
    explicit SegmentTree(int n) : size(n), tree((size << 1) - 1) {}

    void initialize(std::vector<Point>& arr) {
        build(arr, 1, 0, size - 1);
    }

    void update(int left, int right, const Point& newValue) {
        updateRange(left, right, newValue, 1, 0, size - 1);
    }

    Point query(int left, int right) {
        return queryRange(left, right, 1, 0, size - 1);
    }
};

